    <form method="post">
        <input asp-for="Product.ProductId" type="hidden" />

        <div class="form-group">
            <label asp-for="Product.ProductName">Tên sản phẩm <span style="color:red;">*</span></label>
            <input asp-for="Product.ProductName" placeholder="Nhập tên sản phẩm" />
            <span asp-validation-for="Product.ProductName" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitPrice">Giá (đ)</label>
            <input asp-for="Product.UnitPrice" type="number" step="0.01" placeholder="Nhập giá" />
            <span asp-validation-for="Product.UnitPrice" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitsInStock">Tồn kho</label>
            <input asp-for="Product.UnitsInStock" type="number" placeholder="Nhập số lượng tồn" />
            <span asp-validation-for="Product.UnitsInStock" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.UnitsOnOrder">Số lượng đặt hàng</label>
            <input asp-for="Product.UnitsOnOrder" type="number" placeholder="Nhập số lượng đặt" />
            <span asp-validation-for="Product.UnitsOnOrder" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.ReorderLevel">Mức tái đặt hàng</label>
            <input asp-for="Product.ReorderLevel" type="number" placeholder="Nhập mức tái đặt" />
            <span asp-validation-for="Product.ReorderLevel" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label asp-for="Product.QuantityPerUnit">Số lượng trên đơn vị</label>
            <input asp-for="Product.QuantityPerUnit" placeholder="Ví dụ: 10 hộp/thùng" />
            <span asp-validation-for="Product.QuantityPerUnit" class="validation-error"></span>
        </div>

        <div class="form-group">
            <label class="checkbox-label">
                <input asp-for="Product.Discontinued" type="checkbox" />
                <span>Ngừng bán</span>
            </label>
            <span asp-validation-for="Product.Discontinued" class="validation-error"></span>
        </div>

        <div class="form-actions">
            <button type="submit"> Lưu thay đổi</button>
        </div>
    </form>
</div>

</body>
</html>

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;


public class EditModel : PageModel
{
    private readonly NorthwindContext _context;

    public EditModel(NorthwindContext context)
        _context = context;
    public EditModel(NorthwindContext context)

    [BindProperty]

    public async Task<IActionResult> OnGetAsync(int id)
    {
        var product = await _context.Products.FindAsync(id);
        if (product == null)
            return RedirectToPage("Index");

        Product = product;
        return Page();
    }

    public async Task<IActionResult> OnPostAsync()
    {
        if (!ModelState.IsValid)
            return Page();

        var product = await _context.Products.FindAsync(Product.ProductId);
        if (product == null)
            return RedirectToPage("Index");

        product.ProductName = Product.ProductName;
        product.UnitPrice = Product.UnitPrice;
        product.UnitsInStock = Product.UnitsInStock;
        product.UnitsOnOrder = Product.UnitsOnOrder;
        product.ReorderLevel = Product.ReorderLevel;
        product.QuantityPerUnit = Product.QuantityPerUnit;
        product.Discontinued = Product.Discontinued;

        await _context.SaveChangesAsync();
        return RedirectToPage("Index");
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using Microsoft.AspNetCore.SignalR;
using Microsoft.EntityFrameworkCore;
using Module3_ASP_NET_RazorPage.Models;
using Module3_ASP_NET_RazorPage.Hubs;

namespace Module3_ASP_NET_RazorPage.Pages.Products;

public class EditModel : PageModel
{
    private readonly NorthwindContext _context;
    private readonly IHubContext<ProductHub> _hubContext;

    public EditModel(NorthwindContext context, IHubContext<ProductHub> hubContext)
    {
        _context = context;
        _hubContext = hubContext;
    }

    [BindProperty]
    public Product Product { get; set; } = new();

    public async Task<IActionResult> OnGetAsync(int id)
    {
        var product = await _context.Products.FindAsync(id);
        if (product == null)
            return RedirectToPage("Index");

        Product = product;
        return Page();
    }

    public async Task<IActionResult> OnPostAsync()
    {
        if (!ModelState.IsValid)
            return Page();

        var product = await _context.Products.FindAsync(Product.ProductId);
        if (product == null)
            return RedirectToPage("Index");

        product.ProductName = Product.ProductName;
        product.UnitPrice = Product.UnitPrice;
        product.UnitsInStock = Product.UnitsInStock;
        product.UnitsOnOrder = Product.UnitsOnOrder;
        product.ReorderLevel = Product.ReorderLevel;
        product.QuantityPerUnit = Product.QuantityPerUnit;
        product.Discontinued = Product.Discontinued;

        await _context.SaveChangesAsync();
        await _hubContext.Clients.All.SendAsync("ReceiveNotification", new { 
            productId = product.ProductId, 
            productName = product.ProductName, 
            notificationType = "Updated",
            timestamp = DateTime.Now
        });

        return RedirectToPage("Index");
    }
}

@page
@model Module3_ASP_NET_RazorPage.Pages.Products.IndexModel
@addTagHelper *, Microsoft.AspNetCore.Mvc.TagHelpers

<h2>Products</h2>

<div id="message" style="display:none; padding:10px; margin-bottom:10px; border:1px solid #ccc;"></div>

<a href="/Products/Create">Create New</a>

<br /><br />
<table border="1" cellpadding="5" cellspacing="0">
    <thead>
        <tr>
            <th>ID</th>
            <th>Product Name</th>
            <th>Unit Price</th>
            <th>Units In Stock</th>
            <th>Discontinued</th>
            <th>Action</th>
        </tr>
    </thead>
    <tbody id="productsTable">
    </tbody>
</table>

<p id="noProducts" style="display:none;">No products found.</p>

<script src="https://cdnjs.cloudflare.com/ajax/libs/microsoft-signalr/8.0.0/signalr.min.js"></script>
<script>
    const connection = new signalR.HubConnectionBuilder()
        .withUrl("/productHub")
        .withAutomaticReconnect()
        .build();

    let products = [];

    function showMessage(text) {
        const msg = document.getElementById('message');
        msg.textContent = text;
        msg.style.display = 'block';
        setTimeout(() => {
            msg.style.display = 'none';
        }, 3000);
    }

    async function loadProducts() {
        const response = await fetch('/Products?handler=GetProducts');
        if (response.ok) {
            products = await response.json();
            renderProducts();
        }
    }

    function renderProducts() {
        const tbody = document.getElementById('productsTable');
        const noProducts = document.getElementById('noProducts');

        tbody.innerHTML = '';

        if (products.length === 0) {
            noProducts.style.display = 'block';
            return;
        }

        noProducts.style.display = 'none';

        products.forEach(p => {
            const row = tbody.insertRow();
            row.id = 'product-' + p.productId;
            row.innerHTML = `
                <td>${p.productId}</td>
                <td>${p.productName}</td>
                <td>${p.unitPrice}</td>
                <td>${p.unitsInStock}</td>
                <td>${p.discontinued ? 'Yes' : 'No'}</td>
                <td>
                    <a href="/Products/Edit?id=${p.productId}">Edit</a>
                    |
                    <button onclick="deleteProduct(${p.productId})">Delete</button>
                </td>
            `;
        });
    }

    function deleteProduct(id) {
        if (confirm('Delete this product?')) {
            const form = document.createElement('form');
            form.method = 'POST';
            form.innerHTML = `
                <input type="hidden" name="id" value="${id}" />
                <input type="hidden" name="handler" value="Delete" />
            `;
            document.body.appendChild(form);
            form.submit();
        }
    }

    connection.on("ProductAdded", (productId, productName) => {
        showMessage('Product added: ' + productName);
        loadProducts();
    });

    connection.on("ProductUpdated", (productId, productName) => {
        showMessage('Product updated: ' + productName);
        loadProducts();
    });

    connection.on("ProductDeleted", (productId) => {
        showMessage('Product deleted');
        const row = document.getElementById('product-' + productId);
        if (row) {
            row.remove();
        }
        products = products.filter(p => p.productId !== productId);
        if (products.length === 0) {
            document.getElementById('noProducts').style.display = 'block';
        }
    });

    connection.start().catch(err => console.error(err));

    loadProducts();
</script>

